// Reaktiv Kafka Consumer til ladedata
@ApplicationScoped
public class ChargingStationConsumer {

    @Inject
    ChargingService chargingService;

    @Incoming("charging-sessions")
    @Acknowledgment(Acknowledgment.Strategy.MANUAL)
    public Uni<Void> processSession(Message<String> message) {
        String payload = message.getPayload();

        return chargingService.validateAndSave(payload)
            .onItem().transformToUni(v -> Uni.createFrom().completionStage(message.ack()))
            .onFailure().recoverWithUni(err -> {
                // Fejlhåndtering & Dead-Letter-Queue
                return Uni.createFrom().completionStage(message.nack(err));
            });
    }
}
